mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT * FROM ( SELECT b.POST_SEQ, b.TITLE, b.CATEGORY, b.USERS_ID, b.VIEW_COUNT, b.CREATED_AT, u.NAME AS AUTHOR_NAME, ROW_NUMBER() OVER (ORDER BY b.CREATED_AT DESC) AS row_rank FROM BOARD_POSTS b LEFT JOIN USERS u ON b.USERS_ID = u.ID WHERE b.CATEGORY = '자유' )
AND (TITLE LIKE '%' || #{keyword} || '%' OR AUTHOR_NAME LIKE '%' || #{keyword} || '%')
ORDER BY CREATED_AT DESC ) a WHERE ROWNUM <= #{end} ) WHERE rn BETWEEN #{start} AND #{end}

mapper.update:
UPDATE BOARD_POSTS
SET VIEW_COUNT = VIEW_COUNT + 1
WHERE POST_SEQ = #{post_seq}

UPDATE BOARD_POSTS
SET TITLE = #{title},
    CATEGORY = #{category},
    CONTENT = #{content}
WHERE POST_SEQ = #{post_seq}
